/* PasstheEPPP — Content Data */
const EPPPData = {
domains: [
{id:1,name:"Biological Bases of Behavior",weight:10,color:"#6EE7B7",
topics:[
{title:"Neuroanatomy",summary:"The nervous system is divided into the CNS (brain & spinal cord) and PNS (somatic & autonomic). Key brain structures: **Cerebral cortex** (frontal—executive function, parietal—somatosensory, temporal—auditory/memory, occipital—vision). **Limbic system**: hippocampus (memory consolidation), amygdala (emotion/fear), hypothalamus (homeostasis, motivation). **Basal ganglia** control voluntary movement; damage → Parkinson's/Huntington's. **Cerebellum** coordinates movement, balance. **Brain stem** (medulla, pons, midbrain) controls vital functions. Broca's area (left frontal) = speech production; Wernicke's area (left temporal) = language comprehension. **Corpus callosum** connects hemispheres. Prefrontal cortex is crucial for planning, impulse control, and working memory."},
{title:"Neurotransmitters & Psychopharmacology",summary:"Key neurotransmitters: **Dopamine** — reward, motivation, movement (low → depression/Parkinson's; high → schizophrenia). **Serotonin** — mood, sleep, appetite (low → depression, OCD; SSRIs increase availability). **Norepinephrine** — arousal, alertness (involved in fight-or-flight). **GABA** — primary inhibitory NT (low → anxiety; benzodiazepines enhance). **Glutamate** — primary excitatory NT (excess → excitotoxicity). **Acetylcholine** — memory, muscle contraction (low → Alzheimer's). **Endorphins** — pain reduction, pleasure. Drug mechanisms: agonists mimic/enhance NT; antagonists block receptors. Antipsychotics block dopamine (D2). MAOIs prevent NT breakdown. SSRIs/SNRIs block reuptake selectively."},
{title:"Neuroplasticity & Genetics",summary:"**Neuroplasticity** — brain's ability to reorganize. Greatest in childhood but continues throughout life. Types: synaptic (strengthening/weakening connections), structural (new dendrites/synapses), functional (reassigning functions after injury). **Long-term potentiation (LTP)** — strengthening synapses through repeated stimulation; basis of learning/memory. **Behavioral genetics**: heritability estimates from twin/adoption studies. Concordance rates higher in MZ than DZ twins for schizophrenia (~48% vs ~17%), bipolar, autism. **Epigenetics** — environmental factors alter gene expression without changing DNA sequence. **Diathesis-stress model** — genetic predisposition + environmental stressor → disorder."}
],
flashcards:[
{front:"What are the two divisions of the nervous system?",back:"Central Nervous System (CNS: brain + spinal cord) and Peripheral Nervous System (PNS: somatic + autonomic)"},
{front:"What does Broca's area control?",back:"Speech production (left frontal lobe). Damage causes Broca's aphasia — nonfluent, effortful speech with intact comprehension."},
{front:"What does Wernicke's area control?",back:"Language comprehension (left temporal lobe). Damage causes fluent but meaningless speech with poor comprehension."},
{front:"What is the function of the hippocampus?",back:"Memory consolidation — transferring short-term to long-term memory. Damage causes anterograde amnesia (e.g., Patient H.M.)."},
{front:"What neurotransmitter is most associated with Parkinson's disease?",back:"Dopamine — degeneration of dopaminergic neurons in the substantia nigra causes motor symptoms."},
{front:"What is the mechanism of SSRIs?",back:"Selective Serotonin Reuptake Inhibitors block the reuptake of serotonin, increasing its availability in the synaptic cleft."},
{front:"What is Long-Term Potentiation (LTP)?",back:"Strengthening of synaptic connections through repeated stimulation — the neural basis of learning and memory."},
{front:"Define the diathesis-stress model.",back:"A psychological model stating that disorders result from the interaction of genetic vulnerability (diathesis) and environmental stressors."},
{front:"What is the primary inhibitory neurotransmitter?",back:"GABA (gamma-aminobutyric acid). Low levels associated with anxiety. Benzodiazepines enhance GABA activity."},
{front:"What does the amygdala do?",back:"Processes emotions, especially fear and aggression. Central to fear conditioning and emotional memory."}
],
questions:[
{q:"A patient can understand speech but produces fragmented, effortful output. Which area is most likely damaged?",options:["Wernicke's area","Broca's area","Angular gyrus","Arcuate fasciculus"],answer:1,rationale:"Broca's aphasia (expressive aphasia) results from damage to Broca's area in the left frontal lobe, producing nonfluent speech with relatively preserved comprehension.",difficulty:"medium"},
{q:"Which neurotransmitter is primarily targeted by benzodiazepines?",options:["Serotonin","Dopamine","GABA","Norepinephrine"],answer:2,rationale:"Benzodiazepines are positive allosteric modulators of GABA-A receptors, enhancing the inhibitory effect of GABA to reduce anxiety.",difficulty:"easy"},
{q:"The dopamine hypothesis of schizophrenia suggests:",options:["Too little dopamine in all brain pathways","Excess dopamine activity in mesolimbic pathway","Serotonin-dopamine imbalance in the cortex","Norepinephrine excess in the limbic system"],answer:1,rationale:"The dopamine hypothesis posits that hyperactive dopamine transmission in the mesolimbic pathway contributes to positive symptoms of schizophrenia.",difficulty:"medium"},
{q:"Patient H.M.'s bilateral hippocampal removal primarily impaired his ability to:",options:["Retrieve childhood memories","Form new long-term declarative memories","Perform learned motor tasks","Recognize familiar faces"],answer:1,rationale:"H.M. had severe anterograde amnesia — inability to form new declarative memories — while procedural memory and most remote memories were spared.",difficulty:"medium"},
{q:"Which brain structure is the primary relay station for sensory information (except olfaction)?",options:["Hypothalamus","Hippocampus","Thalamus","Amygdala"],answer:2,rationale:"The thalamus relays all sensory information (except smell) to the appropriate cortical areas for processing.",difficulty:"easy"},
{q:"A researcher finds 48% concordance for schizophrenia in MZ twins and 17% in DZ twins. This suggests:",options:["Schizophrenia is entirely genetic","Both genetic and environmental factors contribute","Environment is the sole cause","The study is invalid"],answer:1,rationale:"MZ > DZ concordance indicates genetic influence, but rates below 100% in MZ twins demonstrate significant environmental contribution.",difficulty:"medium"},
{q:"Which lobe contains the primary motor cortex?",options:["Parietal","Temporal","Frontal","Occipital"],answer:2,rationale:"The primary motor cortex is located in the precentral gyrus of the frontal lobe, controlling voluntary movement.",difficulty:"easy"},
{q:"Anterograde amnesia involves difficulty with:",options:["Recalling events before the injury","Forming new memories after the injury","Procedural learning","Implicit memory tasks"],answer:1,rationale:"Anterograde amnesia is the inability to form new memories after the onset of the condition, while retrograde amnesia affects memories before onset.",difficulty:"easy"},
{q:"The myelin sheath functions primarily to:",options:["Generate neurotransmitters","Increase speed of neural impulse conduction","Store memories in dendrites","Provide nutrients to the soma"],answer:1,rationale:"Myelin insulates axons and enables saltatory conduction, dramatically increasing the speed of action potential propagation.",difficulty:"easy"},
{q:"What is epigenetics?",options:["Changes to DNA sequence caused by mutation","Heritable changes in gene expression without DNA alteration","Gene therapy techniques","Statistical analysis of genetic data"],answer:1,rationale:"Epigenetics involves modifications (e.g., methylation, histone changes) that alter gene expression without changing the underlying DNA sequence.",difficulty:"medium"}
]},

{id:2,name:"Cognitive-Affective Bases of Behavior",weight:13,color:"#60A5FA",
topics:[
{title:"Learning Theories",summary:"**Classical conditioning** (Pavlov): pairing neutral stimulus (CS) with unconditioned stimulus (UCS) to produce conditioned response. Key concepts: acquisition, extinction, spontaneous recovery, stimulus generalization, discrimination. **Operant conditioning** (Skinner): behavior shaped by consequences. Reinforcement (positive/negative) increases behavior; punishment decreases. Schedules: fixed-ratio, variable-ratio, fixed-interval, variable-interval. VR produces highest, most consistent response rates. **Observational learning** (Bandura): learning through modeling. Bobo doll study. Requires attention, retention, reproduction, motivation. **Learned helplessness** (Seligman): exposure to uncontrollable events leads to passive behavior and depression-like symptoms."},
{title:"Memory Systems",summary:"**Atkinson-Shiffrin model**: sensory → short-term → long-term memory. **Working memory** (Baddeley): central executive, phonological loop, visuospatial sketchpad, episodic buffer. **Long-term memory**: declarative (explicit) — episodic (personal events) + semantic (facts/knowledge); nondeclarative (implicit) — procedural, priming, conditioning. **Encoding**: levels of processing (Craik & Lockhart) — deeper semantic processing = better retention. **Retrieval**: recall vs recognition. Context-dependent and state-dependent memory effects. **Forgetting**: interference (proactive = old disrupts new; retroactive = new disrupts old), decay theory, motivated forgetting. **Memory errors**: misinformation effect (Loftus), source monitoring errors, false memories."},
{title:"Emotion & Motivation",summary:"**James-Lange**: experience emotion after physiological arousal. **Cannon-Bard**: arousal and emotion occur simultaneously. **Schachter-Singer (two-factor)**: emotion = physiological arousal + cognitive label. **Lazarus**: cognitive appraisal precedes emotion. **Maslow's hierarchy**: physiological → safety → belonging → esteem → self-actualization. **Self-determination theory** (Deci & Ryan): autonomy, competence, relatedness. Intrinsic vs extrinsic motivation — overjustification effect: external rewards can undermine intrinsic motivation. **Ekman**: 6 universal emotions (happiness, sadness, anger, fear, disgust, surprise)."}
],
flashcards:[
{front:"What is the difference between positive and negative reinforcement?",back:"Both INCREASE behavior. Positive = adding a pleasant stimulus. Negative = removing an aversive stimulus."},
{front:"What schedule of reinforcement produces the highest response rate?",back:"Variable-ratio (VR) schedule — produces high, steady response rates with high resistance to extinction (e.g., slot machines)."},
{front:"Name the components of Baddeley's working memory model.",back:"Central executive (attention controller), phonological loop (verbal/auditory info), visuospatial sketchpad (visual/spatial info), episodic buffer (integrates information)."},
{front:"What is proactive interference?",back:"Old memories interfere with the recall of newer information. Example: calling your new partner by your ex's name."},
{front:"What is the misinformation effect?",back:"Loftus's finding that post-event information can distort memory of the original event. Leading questions alter eyewitness recall."},
{front:"Describe Schachter-Singer two-factor theory.",back:"Emotion requires two components: (1) physiological arousal and (2) cognitive interpretation/label of that arousal."},
{front:"What is learned helplessness?",back:"Seligman's theory: after experiencing uncontrollable events, organisms learn to be passive and stop attempting to escape, even when escape is possible. Model for depression."},
{front:"What is the overjustification effect?",back:"When external rewards are given for intrinsically motivated behavior, intrinsic motivation decreases once the reward is removed."}
],
questions:[
{q:"A child bitten by a dog becomes afraid of all furry animals. This demonstrates:",options:["Stimulus discrimination","Stimulus generalization","Higher-order conditioning","Extinction"],answer:1,rationale:"Stimulus generalization occurs when a conditioned response transfers to stimuli similar to the original CS (dog → all furry animals).",difficulty:"easy"},
{q:"Which reinforcement schedule is MOST resistant to extinction?",options:["Fixed-ratio","Fixed-interval","Variable-ratio","Continuous"],answer:2,rationale:"Variable-ratio schedules produce the highest rates of responding and greatest resistance to extinction because reinforcement is unpredictable.",difficulty:"easy"},
{q:"In Baddeley's model, the component responsible for integrating information from multiple sources is the:",options:["Phonological loop","Visuospatial sketchpad","Episodic buffer","Central executive"],answer:2,rationale:"The episodic buffer integrates information from the phonological loop, visuospatial sketchpad, and long-term memory into coherent episodes.",difficulty:"medium"},
{q:"A student studies Spanish after years of French and finds French vocabulary intruding. This is:",options:["Retroactive interference","Proactive interference","Decay","Repression"],answer:1,rationale:"Proactive interference: previously learned French interferes with retrieval of newly learned Spanish.",difficulty:"medium"},
{q:"According to Maslow, which need must be met first?",options:["Esteem","Belonging","Safety","Self-actualization"],answer:2,rationale:"Maslow's hierarchy is: physiological → safety → belonging → esteem → self-actualization. Safety needs come before belonging and esteem.",difficulty:"easy"},
{q:"Bandura's Bobo doll experiment primarily demonstrated:",options:["Classical conditioning of aggression","Operant conditioning principles","Observational learning","Instinctive drift"],answer:2,rationale:"Children who observed an adult model aggressive behavior toward the Bobo doll imitated that aggression, demonstrating observational/social learning.",difficulty:"easy"},
{q:"Loftus's research on eyewitness testimony showed that:",options:["Memory is a perfect recording","Post-event information can alter memory","Hypnosis improves recall","Children are more accurate witnesses"],answer:1,rationale:"Loftus demonstrated the misinformation effect — leading questions and post-event info can distort original memories.",difficulty:"easy"},
{q:"The James-Lange theory suggests that:",options:["Cognition determines emotion","Emotion and arousal occur simultaneously","We feel emotions after perceiving physiological responses","Emotions are universally expressed"],answer:2,rationale:"James-Lange: stimulus → physiological arousal → interpretation of arousal as emotion. We feel afraid because we run, not the reverse.",difficulty:"medium"},
{q:"Self-determination theory identifies three basic psychological needs:",options:["Safety, esteem, belonging","Autonomy, competence, relatedness","Id, ego, superego","Achievement, power, affiliation"],answer:1,rationale:"Deci & Ryan's SDT posits autonomy, competence, and relatedness as innate needs essential for intrinsic motivation and well-being.",difficulty:"medium"},
{q:"Retroactive interference occurs when:",options:["Old learning disrupts new recall","New learning disrupts old recall","Both old and new are forgotten equally","Neither interferes with the other"],answer:1,rationale:"Retroactive interference: newly learned material interferes with retrieval of previously learned material.",difficulty:"easy"}
]},

{id:3,name:"Social & Cultural Bases of Behavior",weight:11,color:"#F472B6",
topics:[
{title:"Social Cognition & Attitudes",summary:"**Attribution theory**: internal (dispositional) vs external (situational) attributions. **Fundamental attribution error** (FAE): overestimating dispositional and underestimating situational factors for others' behavior. **Self-serving bias**: attribute successes internally, failures externally. **Cognitive dissonance** (Festinger): discomfort from holding contradictory beliefs → motivation to reduce. **Attitudes**: ABC model (Affect, Behavior, Cognition). **Elaboration Likelihood Model** (Petty & Cacioppo): central route (careful processing) vs peripheral route (superficial cues). **Halo effect**: one positive trait colors overall impression."},
{title:"Group Dynamics & Influence",summary:"**Conformity** (Asch): yielding to group pressure even when clearly wrong (~37% conformed). **Obedience** (Milgram): 65% administered maximum 'shocks' when instructed by authority. **Groupthink** (Janis): desire for harmony → poor decision-making. **Social facilitation**: presence of others enhances performance on simple tasks, impairs complex tasks. **Social loafing**: reduced individual effort in groups. **Deindividuation**: loss of self-awareness in groups → uninhibited behavior. **Bystander effect** (Darley & Latané): more bystanders = less likely any will help (diffusion of responsibility)."},
{title:"Cultural & Diversity Issues",summary:"**Individualism vs collectivism**: Western cultures emphasize individual achievement; Eastern cultures emphasize group harmony. **Acculturation strategies** (Berry): integration, assimilation, separation, marginalization. **Multicultural competence**: awareness of own biases, knowledge of diverse populations, culturally appropriate skills. **Stereotype threat** (Steele): awareness of negative stereotypes can impair performance. **Microaggressions**: subtle, often unintentional slights based on group membership. **Intersectionality**: multiple identities (race, gender, SES) interact to shape experience of privilege and oppression."}
],
flashcards:[
{front:"What is the fundamental attribution error?",back:"The tendency to overattribute others' behavior to dispositional (internal) factors while underestimating situational (external) factors."},
{front:"Describe cognitive dissonance.",back:"Festinger's theory: holding contradictory cognitions creates psychological discomfort, motivating attitude or behavior change to restore consistency."},
{front:"What did Milgram's obedience study find?",back:"65% of participants administered the maximum 450V 'shock' when ordered by an authority figure, demonstrating the power of situational authority."},
{front:"What is the bystander effect?",back:"The more bystanders present, the less likely any individual is to help — due to diffusion of responsibility and pluralistic ignorance."},
{front:"Name Berry's four acculturation strategies.",back:"Integration (maintain culture + participate in new), Assimilation (adopt new, abandon old), Separation (maintain old, reject new), Marginalization (neither)."},
{front:"What is stereotype threat?",back:"Steele's finding that awareness of negative stereotypes about one's group can cause anxiety and impair performance on relevant tasks."}
],
questions:[
{q:"A manager attributes an employee's lateness to laziness rather than traffic. This best illustrates:",options:["Self-serving bias","Fundamental attribution error","Actor-observer effect","Just-world hypothesis"],answer:1,rationale:"The FAE involves overattributing behavior to dispositional causes (laziness) while underestimating situational factors (traffic).",difficulty:"easy"},
{q:"In Asch's conformity studies, approximately what percentage of participants conformed at least once?",options:["15%","37%","55%","75%"],answer:3,rationale:"About 75% of participants conformed at least once. The average conformity rate across all trials was approximately 37%, meaning on average about one-third of responses were conforming.",difficulty:"medium"},
{q:"Groupthink is BEST prevented by:",options:["Having a strong, directive leader","Encouraging unanimous agreement early","Assigning a devil's advocate role","Increasing group cohesion"],answer:2,rationale:"Devil's advocate role encourages critical evaluation, reducing the pressure for premature consensus that characterizes groupthink.",difficulty:"medium"},
{q:"The Elaboration Likelihood Model's central route involves:",options:["Quick judgments based on source attractiveness","Careful evaluation of argument quality","Emotional responses to messages","Automatic processing of peripheral cues"],answer:1,rationale:"Central route: systematic, thoughtful evaluation of message content and argument quality. More durable attitude change.",difficulty:"medium"},
{q:"Which acculturation strategy involves maintaining one's heritage culture while participating in the new culture?",options:["Assimilation","Separation","Integration","Marginalization"],answer:2,rationale:"Integration involves maintaining the original culture while actively participating in the dominant culture — associated with best outcomes.",difficulty:"easy"},
{q:"Social facilitation theory predicts that an audience will:",options:["Always improve performance","Improve simple task performance, impair complex","Always impair performance","Have no systematic effect"],answer:1,rationale:"Zajonc's social facilitation theory: audience presence increases arousal, which enhances dominant responses — helping simple tasks, hurting complex ones.",difficulty:"medium"},
{q:"A woman performs worse on a math test after being reminded of gender stereotypes. This demonstrates:",options:["Self-fulfilling prophecy","Stereotype threat","Confirmation bias","Implicit bias"],answer:1,rationale:"Stereotype threat (Steele & Aronson): making negative group stereotypes salient impairs performance on stereotype-relevant tasks.",difficulty:"easy"},
{q:"Cognitive dissonance is MOST likely when:",options:["Behavior is coerced","Behavior is freely chosen and contradicts beliefs","External justification is high","The behavior has no consequences"],answer:1,rationale:"Dissonance is greatest when behavior is freely chosen with minimal external justification, creating internal pressure to change attitudes.",difficulty:"medium"}
]},

{id:4,name:"Growth & Lifespan Development",weight:12,color:"#FBBF24",
topics:[
{title:"Cognitive Development",summary:"**Piaget's stages**: Sensorimotor (0-2, object permanence), Preoperational (2-7, egocentrism, conservation failure, symbolic play), Concrete operational (7-11, conservation, classification, seriation), Formal operational (11+, abstract/hypothetical thinking). **Vygotsky**: Zone of Proximal Development (ZPD) — gap between independent and assisted ability. Scaffolding. Social-cultural emphasis. **Information processing**: gradual improvements in attention, memory, processing speed. Theory of mind develops ~age 4."},
{title:"Psychosocial & Moral Development",summary:"**Erikson's 8 stages**: Trust vs Mistrust (0-1), Autonomy vs Shame (1-3), Initiative vs Guilt (3-6), Industry vs Inferiority (6-12), Identity vs Role Confusion (12-18), Intimacy vs Isolation (young adult), Generativity vs Stagnation (middle), Integrity vs Despair (late). **Kohlberg's moral development**: Preconventional (punishment/reward), Conventional (social approval/law and order), Postconventional (social contract/universal principles). **Gilligan** critiqued Kohlberg for male bias — proposed ethic of care."},
{title:"Attachment & Aging",summary:"**Bowlby**: attachment is adaptive; internal working models. **Ainsworth's Strange Situation**: Secure, Insecure-Avoidant, Insecure-Ambivalent/Resistant, Disorganized (Main & Hesse). Secure attachment → better outcomes. **Temperament** (Thomas & Chess): easy, difficult, slow-to-warm-up. **Aging**: crystallized intelligence stable/increases; fluid intelligence declines. Selective optimization with compensation (Baltes). **Kübler-Ross** stages of grief: Denial, Anger, Bargaining, Depression, Acceptance (not strictly sequential). **Successful aging** involves social engagement, cognitive activity, physical health."}
],
flashcards:[
{front:"List Piaget's four stages in order.",back:"1) Sensorimotor (0-2): object permanence\n2) Preoperational (2-7): egocentrism\n3) Concrete operational (7-11): conservation\n4) Formal operational (11+): abstract thought"},
{front:"What is the Zone of Proximal Development?",back:"Vygotsky's concept: the gap between what a learner can do independently and what they can do with guidance. Learning occurs within this zone via scaffolding."},
{front:"Name Erikson's crisis for adolescence.",back:"Identity vs. Role Confusion (ages 12-18). Successful resolution = coherent sense of self; failure = identity diffusion."},
{front:"Name Ainsworth's attachment types.",back:"Secure (distressed at separation, comforted at reunion), Insecure-Avoidant (little distress, ignores caregiver), Insecure-Ambivalent (very distressed, resists comfort), Disorganized (contradictory, confused behaviors)."},
{front:"Kohlberg's three levels of moral development?",back:"1) Preconventional: self-interest (punishment avoidance, reward)\n2) Conventional: social norms (approval, law and order)\n3) Postconventional: abstract principles (social contract, universal ethics)"},
{front:"Crystallized vs. fluid intelligence in aging?",back:"Crystallized (accumulated knowledge/vocabulary) remains stable or increases. Fluid (novel problem-solving, processing speed) declines with age."}
],
questions:[
{q:"A 5-year-old thinks the moon follows her when she walks. This reflects Piaget's concept of:",options:["Object permanence","Animism/egocentrism","Conservation","Hypothetical thinking"],answer:1,rationale:"Preoperational children display egocentrism (difficulty taking others' perspectives) and animism (attributing life to inanimate objects).",difficulty:"easy"},
{q:"Vygotsky's ZPD is BEST applied through:",options:["Allowing children to discover solutions alone","Scaffolding instruction within capability range","Drill and practice of memorized facts","Standardized testing"],answer:1,rationale:"Scaffolding provides temporary, tailored support within the ZPD, gradually withdrawn as competence grows.",difficulty:"easy"},
{q:"In Ainsworth's Strange Situation, a child who shows distress upon separation and seeks comfort upon reunion is classified as:",options:["Avoidant","Secure","Ambivalent","Disorganized"],answer:1,rationale:"Securely attached children show distress at separation, are comforted by caregiver's return, and use caregiver as secure base.",difficulty:"easy"},
{q:"Kohlberg's conventional level of morality is characterized by:",options:["Self-interest and avoiding punishment","Following rules to maintain social order","Acting on universal ethical principles","Maximizing personal gain"],answer:1,rationale:"Conventional morality (Stages 3-4): behaviors guided by desire for social approval and adherence to laws and authority.",difficulty:"easy"},
{q:"Erikson's generativity vs. stagnation stage occurs during:",options:["Adolescence","Young adulthood","Middle adulthood","Late adulthood"],answer:2,rationale:"Generativity vs. Stagnation (middle adulthood, ~40-65): focus on productive contributions to society and guiding the next generation.",difficulty:"easy"},
{q:"Which type of intelligence tends to INCREASE with age?",options:["Fluid intelligence","Processing speed","Crystallized intelligence","Inhibitory control"],answer:2,rationale:"Crystallized intelligence (accumulated knowledge, vocabulary) tends to remain stable or increase throughout adulthood.",difficulty:"easy"},
{q:"Gilligan criticized Kohlberg's theory primarily for:",options:["Not including enough stages","Gender bias favoring male moral reasoning","Ignoring cognitive development","Being culturally universal"],answer:1,rationale:"Gilligan argued Kohlberg's stages reflected a male-oriented justice perspective, neglecting a care-based moral orientation more common in women.",difficulty:"medium"},
{q:"Object permanence is a hallmark achievement of which Piagetian stage?",options:["Preoperational","Sensorimotor","Concrete operational","Formal operational"],answer:1,rationale:"Object permanence (understanding objects exist when out of sight) develops during the sensorimotor stage (0-2 years).",difficulty:"easy"}
]}
],

getDomain(id) { return this.domains.find(d => d.id === id); },
// Normalize a question: ensure `answer` (from `correct` if needed), default `difficulty`
_normalize(q, domainId, domainName) {
    const n = {...q, domainId, domainName};
    // Some batch files use `correct` instead of `answer`
    if (n.answer === undefined && n.correct !== undefined) n.answer = n.correct;
    // Default difficulty if missing
    if (!n.difficulty) n.difficulty = 'medium';
    return n;
},
getAllQuestions() { return this.domains.flatMap(d => d.questions.map(q => this._normalize(q, d.id, d.name))); },
getQuestionsByDomain(id) { const d = this.getDomain(id); return d ? d.questions.map(q => this._normalize(q, id, d.name)) : []; }
};

